/**
 * Lightweight notification service for bulletpoint-sdk
 * Mimics the Rezi app's toast notification style
 */

type NotificationType = 'success' | 'error' | 'warning' | 'info';

class NotificationService {
  private container: HTMLElement | null = null;
  private activeToast: HTMLElement | null = null;

  constructor() {
    this.initContainer();
  }

  private initContainer(): void {
    if (typeof window === 'undefined') return;

    let container = document.getElementById('rbp-notification-container');
    if (!container) {
      container = document.createElement('div');
      container.id = 'rbp-notification-container';
      container.className = 'rbp-notification-container';
      document.body.appendChild(container);
    }
    this.container = container;
  }

  notify(
    message: string,
    type: NotificationType = 'info',
    duration = 3000,
  ): void {
    if (!this.container) return;

    // Remove existing toast if any
    if (this.activeToast) {
      this.activeToast.remove();
      this.activeToast = null;
    }

    const toast = document.createElement('div');
    toast.className = `rbp-toast rbp-toast-${type}`;

    const icon = document.createElement('i');
    if (type === 'success') {
      icon.className = 'fas fa-check';
    }

    const messageEl = document.createElement('span');
    messageEl.textContent = message;

    toast.appendChild(icon);
    toast.appendChild(messageEl);

    this.container.appendChild(toast);
    this.activeToast = toast;

    // Trigger animation
    setTimeout(() => toast.classList.add('rbp-toast-show'), 10);

    // Auto-dismiss (duration = 0 means stay forever)
    if (duration > 0) {
      setTimeout(() => {
        toast.classList.remove('rbp-toast-show');
        setTimeout(() => {
          if (toast.parentNode) toast.remove();
          if (this.activeToast === toast) this.activeToast = null;
        }, 300);
      }, duration);
    }
  }

  success(message: string, duration?: number): void {
    this.notify(message, 'success', duration);
  }

  error(message: string, duration?: number): void {
    this.notify(message, 'error', duration);
  }

  warning(message: string, duration?: number): void {
    this.notify(message, 'warning', duration);
  }

  info(message: string, duration?: number): void {
    this.notify(message, 'info', duration);
  }
}

// Singleton instance
export const notify = new NotificationService();
