/**
 * BulletGenerator Service
 * Generates professional resume bullet points via API
 * Returns error state on failure — no silent fallback
 */

import { getApiConfig } from '../config/api';
import type { ApiConfig } from '../config/api';
import { ApiClient } from './ApiClient';
import { BulletUtils } from '../utils';
import type { RecaptchaService } from './RecaptchaService';
import type {
  BulletGenerateRequest,
  BulletGenerateResponse,
  BulletAPIResponse,
} from '../types';

interface RateLimitData {
  date: string;
  count: number;
}

// localStorage key: "rezi sdk bullet limit"
const LOCAL_STORAGE_KEY = 'rsbl';

export class BulletGenerator {
  private config: ApiConfig;
  private apiClient: ApiClient;

  constructor(isDev: boolean = false, recaptchaService?: RecaptchaService) {
    this.config = getApiConfig(isDev);
    this.apiClient = new ApiClient(this.config, recaptchaService, isDev);
  }

  /**
   * Generate bullet points from API.
   * Returns error state instead of silent fallback.
   */
  async generateBullets(
    params: BulletGenerateRequest,
  ): Promise<BulletGenerateResponse> {
    if (!this.checkRateLimit()) {
      console.warn('[BulletGenerator] Rate limit exceeded');
      return { bullets: [], fromAPI: false, error: 'rate_limit' };
    }

    try {
      const apiBullets = await this.callBulletAPI(params);

      if (apiBullets.error) {
        return apiBullets;
      }

      return { bullets: apiBullets.bullets, fromAPI: true };
    } catch (error) {
      console.error('[BulletGenerator] API call failed:', error);
      return { bullets: [], fromAPI: false, error: 'api_error' };
    }
  }

  /**
   * Single API call to generate bullets
   */
  private async callBulletAPI(
    params: BulletGenerateRequest,
  ): Promise<BulletGenerateResponse> {
    const body: Record<string, unknown> = {
      role: params.jobTitle,
      section: 'experience',
      autocomplete: '',
      lang: 'en',
    };
    if (params.experienceLevel) {
      body['experienceLevel'] = params.experienceLevel;
    }
    if (params.selectedSkills.length > 0) {
      body['skills'] = params.selectedSkills.map((s) => s.name);
    }

    const response = await this.apiClient.post<BulletAPIResponse>(
      this.config.bulletGenerateEndpoint,
      body,
      'ac_public',
    );

    if (response.limit) {
      console.warn('[BulletGenerator] API rate limit reached');
      this.saturateRateLimitCounter();
      return { bullets: [], fromAPI: false, error: 'rate_limit' };
    }

    if (response.error) {
      console.error('[BulletGenerator] API error:', response.error);
      return { bullets: [], fromAPI: false, error: 'api_error' };
    }

    this.incrementRateLimitCounter();

    const bullets = this.parseBullets(response.text);
    return { bullets, fromAPI: true };
  }

  /**
   * Parse bullet points from API response (handles string or string[])
   */
  private parseBullets(text: string | string[]): string[] {
    if (Array.isArray(text)) {
      return text
        .map((line) => line.replace(/^[•\-\*]\s*/, '').trim())
        .filter((line) => line.length > 0);
    }
    return text
      .split('\n')
      .map((line) => line.replace(/^[•\-\*]\s*/, '').trim())
      .filter((line) => line.length > 0);
  }

  private checkRateLimit(): boolean {
    const data = BulletUtils.getLocalData<RateLimitData>(LOCAL_STORAGE_KEY);
    const today = BulletUtils.getTodayKey();
    if (!data || data.date !== today) return true;
    return data.count < this.config.bulletRateLimitPerDay;
  }

  private saturateRateLimitCounter(): void {
    BulletUtils.setLocalData(LOCAL_STORAGE_KEY, {
      date: BulletUtils.getTodayKey(),
      count: this.config.bulletRateLimitPerDay,
    });
  }

  private incrementRateLimitCounter(): void {
    const today = BulletUtils.getTodayKey();
    const data = BulletUtils.getLocalData<RateLimitData>(LOCAL_STORAGE_KEY);

    if (!data || data.date !== today) {
      BulletUtils.setLocalData(LOCAL_STORAGE_KEY, { date: today, count: 1 });
    } else {
      BulletUtils.setLocalData(LOCAL_STORAGE_KEY, {
        date: today,
        count: data.count + 1,
      });
    }
  }
}
