// Experience Level Types
export type ExperienceLevel =
  | 'internship'
  | 'entry-level'
  | 'associate'
  | 'junior-level'
  | 'mid-senior-level'
  | 'director'
  | 'executive';

export interface ExperienceLevelOption {
  value: ExperienceLevel;
  label: string;
}

// Skill Types
export interface Skill {
  id: string;
  name: string;
  category?: string;
  isCustom?: boolean;
}

// SDK Configuration
export interface BulletPointConfig {
  // Required
  containerSelector: string;

  // Optional
  isDev?: boolean;
  theme?: 'light' | 'dark' | 'auto';
  maxSkillSelection?: number; // Default: 5
  bulletPointCount?: number; // Default: 15

  // Callbacks
  onJobTitleChange?: (title: string) => void;
  onSkillsLoaded?: (skills: Skill[]) => void;
  onGenerate?: (bullets: string[]) => void;
  onCopy?: (bullet: string) => void;
  onCTAClick?: (bullets: string[], jobTitle: string) => void;
  onError?: (error: Error) => void;

  // reCAPTCHA Enterprise
  recaptchaSiteKey?: string; // reCAPTCHA Enterprise site key

  // CTA Settings
  ctaUrl?: string; // Redirect URL
}

// API Types
export interface SkillSuggestRequest {
  jobTitle: string;
}

export interface SkillSuggestResponse {
  skills: Skill[];
  fallback?: boolean;
}

export interface BulletGenerateRequest {
  jobTitle: string;
  experienceLevel: ExperienceLevel;
  selectedSkills: Skill[];
  companyInfo?: string;
}

export interface BulletGenerateResponse {
  bullets: string[];
  fromAPI: boolean;
  error?: 'rate_limit' | 'api_error';
}

export interface BulletAPIResponse {
  text: string | string[];
  limit?: boolean;
  error?: string;
}

// Widget State
export type WidgetPhase = 'input' | 'loading' | 'results';

export interface WidgetState {
  // Phase
  phase: WidgetPhase;

  // Input values
  jobTitle: string;
  experienceLevel: ExperienceLevel | null;
  availableSkills: Skill[];
  selectedSkills: Skill[];

  // Results
  generatedBullets: string[];

  // UI state
  isAutocompleteOpen: boolean;
  isExperienceDropdownOpen: boolean;
  copiedBulletIndex: number | null;

  // Error
  error: string | null;
}

// Constants
export const EXPERIENCE_LEVELS: ExperienceLevelOption[] = [
  { value: 'internship', label: 'Internship' },
  { value: 'entry-level', label: 'Entry level' },
  { value: 'associate', label: 'Associate' },
  { value: 'junior-level', label: 'Junior level' },
  { value: 'mid-senior-level', label: 'Mid-Senior level' },
  { value: 'director', label: 'Director' },
  { value: 'executive', label: 'Executive' },
];

export const DEFAULT_MAX_SKILLS = 5;
export const DEFAULT_BULLET_COUNT = 15;
