/**
 * Skill Suggester Service
 * Integrates with /skill-explore API to fetch relevant skills based on job title
 * Falls back to curated data when API is unavailable
 */

import { ApiClient } from './ApiClient';
import type { RecaptchaService } from './RecaptchaService';
import { getApiConfig } from '../config/api';
import type { ApiConfig } from '../config/api';
import { getFallbackSkillsForJob } from '../config/fallback-skills';
import { BulletUtils } from '../utils';
import type { Skill, SkillSuggestResponse } from '../types';

interface SkillExploreApiRequest {
  tool: string;
  context: string;
}

interface SkillExploreApiResponse {
  result: string[];
}

interface RateLimitData {
  date: string;
  count: number;
}

const RATE_LIMIT_STORAGE_KEY = 'rezi_sdk_rate_limit';

export class SkillSuggester {
  private config: ApiConfig;
  private apiClient: ApiClient;
  private isDev: boolean;

  constructor(isDev: boolean = false, recaptchaService?: RecaptchaService) {
    this.isDev = isDev;
    this.config = getApiConfig(isDev);
    this.apiClient = new ApiClient(this.config, recaptchaService);
  }

  /**
   * Get suggested skills for a job title.
   * Returns skills from API or fallback data — never throws.
   */
  async getSuggestedSkills(jobTitle: string): Promise<SkillSuggestResponse> {
    if (!this.checkRateLimit()) {
      console.warn(
        '[SkillSuggester] Rate limit exceeded, using fallback skills',
      );
      return { skills: this.getFallbackSkills(jobTitle), fallback: true };
    }

    try {
      const skills = await this.fetchSkillsFromApi(jobTitle);
      this.incrementRateLimitCounter();
      return { skills, fallback: false };
    } catch (error) {
      console.warn(
        '[SkillSuggester] ⚠️ API failed, using fallback skills:',
        error,
      );
      return { skills: this.getFallbackSkills(jobTitle), fallback: true };
    }
  }

  /**
   * Fetch skills from the /skill-explore API
   */
  private async fetchSkillsFromApi(jobTitle: string): Promise<Skill[]> {
    const requestData: SkillExploreApiRequest = {
      tool: jobTitle,
      context: jobTitle,
    };

    const response = await this.apiClient.post<SkillExploreApiResponse>(
      this.config.skillExploreEndpoint,
      requestData,
      'skill_explore',
    );

    if (!response.result || !Array.isArray(response.result)) {
      throw new Error('Invalid API response format');
    }

    return response.result.map((name, index) => ({
      id: `skill-${index}-${Date.now()}`,
      name: name.trim(),
    }));
  }

  /**
   * Get fallback skills when API is unavailable
   */
  private getFallbackSkills(jobTitle: string): Skill[] {
    return getFallbackSkillsForJob(jobTitle).map((name, index) => ({
      id: `fallback-${index}`,
      name,
    }));
  }

  private checkRateLimit(): boolean {
    try {
      const data = BulletUtils.getLocalData<RateLimitData>(
        RATE_LIMIT_STORAGE_KEY,
      );
      const today = BulletUtils.getTodayKey();
      if (!data || data.date !== today) return true;
      return data.count < this.config.rateLimitPerDay;
    } catch {
      return true;
    }
  }

  private incrementRateLimitCounter(): void {
    try {
      const today = BulletUtils.getTodayKey();
      const data = BulletUtils.getLocalData<RateLimitData>(
        RATE_LIMIT_STORAGE_KEY,
      );

      if (!data || data.date !== today) {
        BulletUtils.setLocalData(RATE_LIMIT_STORAGE_KEY, {
          date: today,
          count: 1,
        });
      } else {
        BulletUtils.setLocalData(RATE_LIMIT_STORAGE_KEY, {
          date: today,
          count: data.count + 1,
        });
      }
    } catch (error) {
      console.warn('[SkillSuggester] Failed to update rate limit:', error);
    }
  }
}
